import { jsPDF } from "jspdf";

var font = '';

const addFont = () => {
  jsPDF.API.events.push([
    "addFonts",
    function () {
      this.addFileToVFS("IRANSansXFaNum-Medium.ttf", font);
      this.addFont("IRANSansXFaNum-Medium.ttf", "IRANSansXFaNum-Medium", "normal");
    }
  ]);
};

export default addFont;
